import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './pages/Login';
import Register from './pages/Register';
import AdminLogin from './pages/AdminLogin';
import UserDashboard from './pages/UserDashboard';
import AdminDashboard from './pages/AdminDashboard';
import Unauthorized from './pages/Unauthorized';
import './App.css';

// ─── ADMIN PROTECTED ROUTE ───────────────────────────────────────────────────
// Blocks access if: not logged in, not ADMIN role, or token missing
const AdminRoute = ({ children }) => {
  const { user, token, loading } = useAuth();
  const location = useLocation();

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  // Not logged in at all → go to admin login
  if (!user || !token) {
    return <Navigate to="/admin/login" state={{ from: location }} replace />;
  }

  // Logged in but NOT admin → show unauthorized page
  if (user.role !== 'ADMIN') {
    return <Navigate to="/unauthorized" replace />;
  }

  return children;
};

// ─── USER PROTECTED ROUTE ────────────────────────────────────────────────────
// Blocks access if: not logged in, or is ADMIN trying to access user pages
const UserRoute = ({ children }) => {
  const { user, token, loading } = useAuth();
  const location = useLocation();

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  if (!user || !token) {
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  // Admin trying to access user dashboard → redirect to admin dashboard
  if (user.role === 'ADMIN') {
    return <Navigate to="/admin/dashboard" replace />;
  }

  return children;
};

// ─── GUEST ROUTE ─────────────────────────────────────────────────────────────
// If already logged in, redirect away from login/register pages
const GuestRoute = ({ children, adminOnly = false }) => {
  const { user, loading } = useAuth();

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;

  if (user) {
    if (user.role === 'ADMIN') return <Navigate to="/admin/dashboard" replace />;
    return <Navigate to="/dashboard" replace />;
  }

  return children;
};

// ─── BACK BUTTON BLOCKER ─────────────────────────────────────────────────────
// Prevents browser back button from going to protected pages after logout
const BackButtonGuard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const adminPaths = ['/admin/dashboard'];
    const userPaths = ['/dashboard'];

    const handlePopState = () => {
      if (!user && adminPaths.includes(location.pathname)) {
        navigate('/admin/login', { replace: true });
      }
      if (!user && userPaths.includes(location.pathname)) {
        navigate('/login', { replace: true });
      }
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, [user, location, navigate]);

  return null;
};

function App() {
  return (
    <AuthProvider>
      <Router>
        <BackButtonGuard />
        <Routes>
          {/* Default */}
          <Route path="/" element={<Navigate to="/login" replace />} />

          {/* Public routes — redirect away if already logged in */}
          <Route path="/login" element={<GuestRoute><Login /></GuestRoute>} />
          <Route path="/register" element={<GuestRoute><Register /></GuestRoute>} />
          <Route path="/admin/login" element={<GuestRoute><AdminLogin /></GuestRoute>} />

          {/* User protected route */}
          <Route path="/dashboard" element={<UserRoute><UserDashboard /></UserRoute>} />

          {/* Admin protected route — ADMIN role only */}
          <Route path="/admin/dashboard" element={<AdminRoute><AdminDashboard /></AdminRoute>} />

          {/* Unauthorized page */}
          <Route path="/unauthorized" element={<Unauthorized />} />

          {/* Catch all unknown routes */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
